class Solution:
    def nextBeautifulNumber(self, n: int) -> int:
        def is_balanced(num):
            count = {}
            for digit in str(num):
                if digit not in count:
                    count[digit] = 0
                count[digit] += 1
            for digit, freq in count.items():
                if int(digit) != freq:
                    return False
            return True

        n += 1
        while not is_balanced(n):
            n += 1
        return n
